<?php
namespace Database\Seeders; use App\Models\Permission; use App\Models\Role; use Illuminate\Database\Seeder;
class ExpensePermissionSeeder extends Seeder { public function run(): void { $permissions=['expenses.view'=>'View expenses','expenses.create'=>'Create expenses','expenses.update'=>'Update expenses','expenses.delete'=>'Archive expenses','expenses.export'=>'Export expenses','expense_categories.view'=>'View expense categories','expense_categories.create'=>'Create expense categories','expense_categories.update'=>'Update expense categories','expense_categories.delete'=>'Delete expense categories']; foreach($permissions as $slug=>$name) Permission::firstOrCreate(['slug'=>$slug],['name'=>$name,'description'=>$name]); if($role=Role::where('name',config('auth.super_admin_role','infra_core_x1'))->first())$role->permissions()->syncWithoutDetaching(Permission::whereIn('slug',array_keys($permissions))->pluck('id')); } }
